  ('medical-tech-moex-10428', 'medical-tech', 'medical-tech-moex-104-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '一位46歲女性病患因皮膚起疹發癢、肝脾腫大與淋巴結腫大來醫院檢查，CBC檢查發現 RBC=3.9 × 1012/L、WBC=25 × 109/L、Platelet=120 × 109/L；血液抹片發現許多細胞膜有 不規則突起（如毛髮狀）的異常單核細胞（如圖），則此病患最可能是下列何種疾病？', '["multiple myeloma", "Hodgkin lymphoma", "hairy cell leukemia", "chronic myeloid leukemia"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:40+00:00", "source_pdf_sha1": "3133e1624977", "answer_pdf_sha1": "f1ea4cbe9b4b", "source_family": "moex-gov-tw", "moex": {"exam_code": "104020", "c": "311", "s": "22", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "104", "exam_name": "104年第一次專技牙醫師藥師分階段考試藥師醫檢師醫放師助產師物理治療師職能呼吸治療師獸醫師考試", "original_question_number": 77, "answer_corrected": false, "flags": [], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
