  ('medical-tech-moex-10432', 'medical-tech', 'medical-tech-moex-104-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '血色素電泳中僅見到Hb A （6.5%）及Hb F（＞90%）時，則下列敘述何者正確？ 2', '["檢體處理不完全，未完全溶血（hemolysate）", "應立即檢查電泳槽的電極是否反置", "懷疑檢體為重度乙型海洋性貧血（β-thalassemia major）", "加做檸檬酸鹽瓊脂電泳（Citrate agar electrophoresis）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:40+00:00", "source_pdf_sha1": "3b8b1491e258", "answer_pdf_sha1": "2883dfc4bf03", "source_family": "moex-gov-tw", "moex": {"exam_code": "104090", "c": "308", "s": "22", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "104", "exam_name": "104年第二次專技醫師牙醫師藥師分階段考試藥師醫檢師醫放師助產師物理職能呼吸治療師獸醫師考試", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
