  ('medical-tech-moex-10434', 'medical-tech', 'medical-tech-moex-104-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', 'fL， MCHC = 30.2 g/dL；週邊血液抹片顯示有不少的target cells、microcytes、 hypochromia和一些RBC fragments；血色素電泳結果顯示：Hb A=82%，Hb A =3.2%，Hb 2 H=14.8%；serum ferritin: 80µg/L；此病人診斷為下列何種疾病？', '["IDA", "α-thalassemia intermedia", "β-thalassemia intermedia", "sideroblastic anemia"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:40+00:00", "source_pdf_sha1": "3b8b1491e258", "answer_pdf_sha1": "2883dfc4bf03", "source_family": "moex-gov-tw", "moex": {"exam_code": "104090", "c": "308", "s": "22", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "104", "exam_name": "104年第二次專技醫師牙醫師藥師分階段考試藥師醫檢師醫放師助產師物理職能呼吸治療師獸醫師考試", "original_question_number": 62, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
