  ('medical-tech-moex-10436', 'medical-tech', 'medical-tech-moex-104-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '有關自體免疫溶血性貧血（AIHA）之敘述，下列何者錯誤？', '["溫型AIHA主要因為IgG或補體附著於紅血球上；DAT test（＋）", "冷型AIHA主要因為IgM附著於紅血球上，其對抗紅血球表面的 I 或 i 抗原", "溫型AIHA，IgG附著於紅血球最適溫度為25℃，發生於SLE和多發性骨髓瘤的併發症", "冷型AIHA，IgM附著於紅血球最適溫度為4℃，發生於黴漿菌的感染"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:40+00:00", "source_pdf_sha1": "3b8b1491e258", "answer_pdf_sha1": "2883dfc4bf03", "source_family": "moex-gov-tw", "moex": {"exam_code": "104090", "c": "308", "s": "22", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "104", "exam_name": "104年第二次專技醫師牙醫師藥師分階段考試藥師醫檢師醫放師助產師物理職能呼吸治療師獸醫師考試", "original_question_number": 4, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
